/// READ FLATFILE
fn flatfile_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_flatfile.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(45);
            if _len > 0 { let _end = _len.min(0+8); state.cm_cust_num = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
            if _len > 8 { let _end = _len.min(8+25); state.cm_company = FixedString::from(String::from_utf8_lossy(&_bytes[8.._end])); }
            if _len > 33 { let _end = _len.min(33+8); state.cm_disk = FixedString::from(String::from_utf8_lossy(&_bytes[33.._end])); }
            if _len > 41 { let _end = _len.min(41+4); let _s = String::from_utf8_lossy(&_bytes[41.._end]).trim().to_string(); state.cm_no_terminals = _s.parse().unwrap_or_default(); }
            state._fs_flatfile = FileStatus::Success;
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
        }
        Err(FileStatus::AtEnd) => {
            state._fs_flatfile = FileStatus::AtEnd;
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
        }
        Err(e) => {
            state._fs_flatfile = e.clone();
    state.cust_stat = FixedString::from(format!("{}", state._fs_flatfile));
        }
    }
    Ok(())
}

/// WRITE to FLATFILE
fn flatfile_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 45];
    { let _src = state.cm_cust_num.as_bytes(); let _end = (0+8).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_company.as_bytes(); let _end = (8+25).min(_buf.len()); let _cl = _src.len().min(_end-8); _buf[8..8+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.cm_disk.as_bytes(); let _end = (33+8).min(_buf.len()); let _cl = _src.len().min(_end-33); _buf[33..33+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.cm_no_terminals, width = 4); let _b = _s.as_bytes(); let _cl = _b.len().min(4); _buf[41..41+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    match state._fh_flatfile.write_record(&_buf) {
        Ok(()) => state._fs_flatfile = FileStatus::Success,
        Err(e) => state._fs_flatfile = e,
    }
}

